// File: jwt_demo.dart
// Run: dart pub add crypto  &&  dart jwt_demo.dart
import 'dart:convert';
import 'package:crypto/crypto.dart';

const secret = 'super-secret-only-server-knows';

String _b64url(List<int> bytes) => base64Url.encode(bytes).replaceAll('=', '');

String signJwt(Map<String, dynamic> payload) {
  final header = _b64url(utf8.encode(jsonEncode({'alg':'HS256','typ':'JWT'})));
  final body   = _b64url(utf8.encode(jsonEncode(payload)));
  final sig = _b64url(Hmac(sha256, utf8.encode(secret))
                        .convert(utf8.encode('$header.$body')).bytes);
  return '$header.$body.$sig';
}

Map<String, dynamic>? verifyJwt(String token) {
  final parts = token.split('.');
  if (parts.length != 3) return null;
  final expected = _b64url(Hmac(sha256, utf8.encode(secret))
                        .convert(utf8.encode('${parts[0]}.${parts[1]}')).bytes);
  if (expected != parts[2]) return null;                   // tampered!
  final claims = jsonDecode(utf8.decode(base64Url.decode(
                     parts[1] + '=' * ((4 - parts[1].length%4)%4)))) as Map<String,dynamic>;
  if (claims['exp'] != null &&
      DateTime.now().millisecondsSinceEpoch ~/ 1000 > claims['exp']) return null; // expired
  return claims;
}

void main() {
  final token = signJwt({
    'sub': 'user-42', 'role': 'admin',
    'exp': DateTime.now().add(Duration(hours: 1)).millisecondsSinceEpoch ~/ 1000,
  });
  print('Token:  $token\n');

  print('--- Anyone can decode the payload ---');
  final payloadB64 = token.split('.')[1];
  print('Payload: ${utf8.decode(base64Url.decode(payloadB64 + "=" * ((4-payloadB64.length%4)%4)))}');

  print('\n--- Real verification ---');
  print('Verify original     : ${verifyJwt(token)}');

  print('\n--- Attacker tries to promote themselves to admin ---');
  final parts = token.split('.');
  final forgedPayload = _b64url(utf8.encode(jsonEncode({
    'sub':'attacker','role':'admin','exp':9999999999})));
  final forged = '${parts[0]}.$forgedPayload.${parts[2]}';
  print('Verify forged token : ${verifyJwt(forged)}');
  print('(null = rejected — the signature no longer matches the payload!)');
}

// Typical output:
// Token:  eyJhbGci...eyJzdWIi...3kF9...
// --- Anyone can decode the payload ---
// Payload: {"sub":"user-42","role":"admin","exp":1893459600}
// --- Real verification ---
// Verify original     : {sub: user-42, role: admin, exp: 1893459600}
// --- Attacker tries to promote themselves to admin ---
// Verify forged token : null
// (null = rejected — the signature no longer matches the payload!)
